-- This module contains shared functions used by [[Module:Category handler]] -- and its submodules.
local function matchesBlacklist(page, blacklist) if type(page) ~= 'string' then return nil end for i, pattern in ipairs(blacklist) do local match = mw.ustring.match(page, pattern) if match then return match end end end
return { matchesBlacklist = matchesBlacklist }

-- This module contains shared functions used by [[Module:Category handler]] -- and its submodules.
local function matchesBlacklist(page, blacklist) for i, pattern in ipairs(blacklist) do local match = mw.ustring.match(page, pattern) if match then return true end end return false end
return { matchesBlacklist = matchesBlacklist }
